{"styles":{"css":".has-most-popular > .most-popular-tag {
 top: -64px;
 left: 50%;
 transform: translateX(-50%
-50%
);
 text-wrap: nowrap;
 width: 100%;
 border-bottom-left-radius: 0px !important;
 border-bottom-right-radius: 0px !important;
 border-top-right-radius: 24px !important;
 border-top-left-radius: 24px !important;
}

.cpg-pricing-table--top, .cpg-pricing-table--sections--section--heading, .cpg-pricing-table--sections--section-item {
border-bottom: 1px solid #D9E5D3 !important;
}

.cpg-pricing-table--sections--section--heading > div, .cpg-pricing-table--sections--section-item > div {
 border-right: 1px solid #D9E5D3 !important;
}

.pricing-table-icon {
background: #FAFFEF;
}

.cpg-pricing-table--top .cpg-pricing-table--top--columnOne, .cpg-pricing-table--top .cpg-pricing-table--top--columnTwo, .cpg-pricing-table--top .cpg-pricing-table--top--columnThree {
 border: 1px solid #D9E5D3 !important;
border-bottom: none !important;
 border-left: none !important;
background: #FAFFEF;
}

.cpg-pricing-table--top--headline{
 border-right: 1px solid #D9E5D3 !important;
}

.cpg-pricing-table--bottom--button1, .cpg-pricing-table--bottom--button2, .cpg-pricing-table--bottom--button3 {
 border-right: 1px solid #D9E5D3 !important;
 border-bottom: 1px solid #D9E5D3 !important;
background: #FAFFEF;
}

.cpg-pricing-table--bottom--button0 {
 border-right: 1px solid #D9E5D3 !important;
}

.cpg-pricing-table--top .cpg-pricing-table--top--columnThree {
border-top-right-radius: 40px !important;
}

.cpg-pricing-table--bottom--button3 {
border-bottom-right-radius: 40px !important;
}

.cpg-pricing-table-wrapper .wp-block-button {
width: 100%;
}"},"isGlobalStylesUserThemeJSON":true,"version":3}
